// Validate and resolve file paths
const inputData = items[0].json;
const fs = require('fs');

let transcriptPath = inputData.file_path;
if (!transcriptPath && inputData.transcript_text) {
  transcriptPath = '/tmp/onboarding_' + Date.now() + '.txt';
  fs.writeFileSync(transcriptPath, inputData.transcript_text);
}

if (!transcriptPath || !fs.existsSync(transcriptPath)) {
  throw new Error('Onboarding transcript file not found');
}

// We need account_id to find v1 data
let account_id = inputData.account_id;
if (!account_id) {
  // Try to infer from filename
  const path = require('path');
  const filename = path.basename(transcriptPath, '.txt');
  account_id = filename.replace(/^onboarding_/, '');
}

const v1MemoPath = '/outputs/accounts/' + account_id + '/v1/memo.json';
if (!fs.existsSync(v1MemoPath)) {
  throw new Error('No v1 memo found for account: ' + account_id + '. Run Pipeline A first.');
}

return [{ json: { file_path: transcriptPath, account_id, v1_memo_path: v1MemoPath } }];

// Parse onboarding transcript and apply updates to v1 memo
const fs = require('fs');
const { parseTranscript } = require('/scripts/parse_transcript');
const { applyUpdates } = require('/scripts/apply_updates');

const data = items[0].json;
const v1Memo = JSON.parse(fs.readFileSync(data.v1_memo_path, 'utf-8'));
const parsed = parseTranscript(data.file_path);
const { v2Memo, changes } = applyUpdates(v1Memo, parsed);

return [{ json: { v1Memo, v2Memo, changes, account_id: data.account_id } }];

// Generate v2 agent spec
const { generateAgentSpec } = require('/scripts/generate_agent');
const data = items[0].json;
const spec = generateAgentSpec(data.v2Memo);
return [{ json: { ...data, spec } }];

// Generate changelog
const { generateChangelog } = require('/scripts/generate_changelog');
const data = items[0].json;
const changelog = generateChangelog(data.account_id, data.v2Memo.company_name, data.changes);
return [{ json: { ...data, changelog } }];

// Write all v2 outputs
const fs = require('fs');
const path = require('path');
const data = items[0].json;
const outputDir = path.join('/outputs/accounts', data.account_id, 'v2');
fs.mkdirSync(outputDir, { recursive: true });

fs.writeFileSync(path.join(outputDir, 'memo.json'), JSON.stringify(data.v2Memo, null, 2));
fs.writeFileSync(path.join(outputDir, 'agent_spec.json'), JSON.stringify(data.spec, null, 2));
fs.writeFileSync(path.join(outputDir, 'changes.json'), JSON.stringify(data.changelog.json, null, 2));
fs.writeFileSync(path.join(outputDir, 'changes.md'), data.changelog.markdown);

return [{ json: {
  status: 'success',
  account_id: data.account_id,
  version: 'v2',
  changes_count: data.changes.length,
  outputs: {
    memo: path.join(outputDir, 'memo.json'),
    agent_spec: path.join(outputDir, 'agent_spec.json'),
    changelog_json: path.join(outputDir, 'changes.json'),
    changelog_md: path.join(outputDir, 'changes.md')
  }
} }];

// Update task tracker
const fs = require('fs');
const data = items[0].json;
const tasksFile = '/outputs/tasks.json';

let tasks = { tasks: [] };
if (fs.existsSync(tasksFile)) {
  tasks = JSON.parse(fs.readFileSync(tasksFile, 'utf-8'));
}

const task = {
  id: 'TASK-' + String(tasks.tasks.length + 1).padStart(3, '0'),
  account_id: data.account_id,
  version: 'v2',
  status: 'completed',
  pipeline: 'Pipeline B (Onboarding → Update)',
  changes_count: data.changes_count,
  created_at: new Date().toISOString(),
  updated_at: new Date().toISOString()
};

tasks.tasks.push(task);
fs.writeFileSync(tasksFile, JSON.stringify(tasks, null, 2));

return [{ json: { ...data, task } }];
